import { LitElement, html, css, nothing, svg } from "lit";
import { customElement, property, state } from "lit/decorators.js";
import type { HomeAssistant, EasyStockCardConfig, StockAttributes } from "./types";

@customElement("easy-stock-card")
export class EasyStockCard extends LitElement {
  private _hass?: HomeAssistant;
  @state() private _entity?: { state: string; attributes: StockAttributes };
  @state() private _config?: EasyStockCardConfig;

  public set hass(hass: HomeAssistant) {
    this._hass = hass;
    if (!this._config) return;
    const next = hass.states[this._config.entity] as unknown as { state: string; attributes: StockAttributes } | undefined;
    if (next !== this._entity) {
      this._entity = next;
    }
  }

  public get hass(): HomeAssistant | undefined {
    return this._hass;
  }

  public setConfig(config: EasyStockCardConfig): void {
    if (!config.entity) throw new Error("easy-stock-card: 'entity' is required.");
    this._config = { show_chart: true, ...config };
  }

  public getCardSize(): number {
    return this._config?.show_chart ? 4 : 2;
  }

  static getStubConfig(): EasyStockCardConfig {
    return { type: "custom:easy-stock-card", entity: "sensor.stock_sap_de", show_chart: true };
  }

  private _sparkline(history: number[]): unknown {
    if (!history || history.length < 2) return nothing;

    const W = 500;
    const H = 80;
    const min = Math.min(...history);
    const max = Math.max(...history);
    const range = max - min || 1;

    const pts = history.map((v, i) => {
      const x = (i / (history.length - 1)) * W;
      const y = H - ((v - min) / range) * H;
      return `${x.toFixed(1)},${y.toFixed(1)}`;
    });

    const first = history[0];
    const last = history[history.length - 1];
    const positive = last >= first;
    const color = positive ? "var(--success-color, #4caf50)" : "var(--error-color, #f44336)";

    // fill polygon
    const fillPts = `0,${H} ${pts.join(" ")} ${W},${H}`;

    return svg`
      <svg viewBox="0 0 ${W} ${H}" preserveAspectRatio="none" xmlns="http://www.w3.org/2000/svg">
        <defs>
          <linearGradient id="sparkGrad" x1="0" y1="0" x2="0" y2="1">
            <stop offset="0%" stop-color="${color}" stop-opacity="0.25"/>
            <stop offset="100%" stop-color="${color}" stop-opacity="0"/>
          </linearGradient>
        </defs>
        <polygon points="${fillPts}" fill="url(#sparkGrad)"/>
        <polyline points="${pts.join(" ")}" fill="none" stroke="${color}" stroke-width="2" stroke-linejoin="round" stroke-linecap="round"/>
      </svg>
    `;
  }

  render() {
    if (!this._config) return nothing;

    if (!this._entity) {
      return html`
        <ha-card>
          <div class="unavailable">Entity not found: ${this._config.entity}</div>
        </ha-card>
      `;
    }

    const price = parseFloat(this._entity.state);
    const attr = this._entity.attributes;
    const positive = attr.change_pct >= 0;
    const changeClass = positive ? "positive" : "negative";
    const changeSign = positive ? "+" : "";
    const title = this._config.title ?? attr.long_name ?? attr.symbol;

    return html`
      <ha-card>
        <div class="container">
          <div class="header">
            <div class="name">${title}</div>
            <div class="symbol">${attr.symbol}</div>
          </div>

          <div class="price-row">
            <div class="price">
              ${isNaN(price) ? "–" : price.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 4 })}
              <span class="currency">${attr.currency}</span>
            </div>
            <div class="change ${changeClass}">
              <span>${changeSign}${attr.change?.toFixed(2)}</span>
              <span class="pct">(${changeSign}${attr.change_pct?.toFixed(2)}%)</span>
            </div>
          </div>

          ${this._config.show_chart && attr.history?.length
            ? html`<div class="chart">${this._sparkline(attr.history)}</div>`
            : nothing}
        </div>
      </ha-card>
    `;
  }

  static styles = css`
    :host {
      display: block;
    }
    .container {
      padding: 16px;
    }
    .unavailable {
      padding: 16px;
      color: var(--secondary-text-color);
      font-style: italic;
    }
    .header {
      display: flex;
      justify-content: space-between;
      align-items: baseline;
      margin-bottom: 8px;
    }
    .name {
      font-size: 1rem;
      font-weight: 500;
      color: var(--primary-text-color);
      white-space: nowrap;
      overflow: hidden;
      text-overflow: ellipsis;
      max-width: 70%;
    }
    .symbol {
      font-size: 0.78rem;
      color: var(--secondary-text-color);
      font-family: monospace;
    }
    .price-row {
      display: flex;
      justify-content: space-between;
      align-items: baseline;
      margin-bottom: 12px;
    }
    .price {
      font-size: 1.8rem;
      font-weight: 700;
      color: var(--primary-text-color);
      line-height: 1;
    }
    .currency {
      font-size: 0.9rem;
      font-weight: 400;
      color: var(--secondary-text-color);
      margin-left: 4px;
    }
    .change {
      font-size: 0.9rem;
      font-weight: 500;
      text-align: right;
    }
    .change.positive {
      color: var(--success-color, #4caf50);
    }
    .change.negative {
      color: var(--error-color, #f44336);
    }
    .pct {
      display: block;
      font-size: 0.8rem;
      opacity: 0.85;
    }
    .chart {
      width: 100%;
      height: 80px;
    }
    .chart svg {
      width: 100%;
      height: 100%;
    }
  `;
}

declare global {
  interface Window {
    customCards?: Array<{ type: string; name: string; description: string }>;
  }
}

window.customCards = window.customCards || [];
window.customCards.push({
  type: "easy-stock-card",
  name: "Easy Stock Card",
  description: "Displays a stock price with 1-year sparkline chart from Yahoo Finance.",
});
